challenges.solution:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

float sdfCircle(vec2 p, float r) { return length(p) - r; }

void main() {
    vec2 uv = (gl_FragCoord.xy / u_resolution) * 2.0 - 1.0;
    uv.x *= u_resolution.x / u_resolution.y;

    float d = sdfCircle(uv, 0.35);

    // Exterior rings
    float rings = 0.5 + 0.5 * sin(d * 40.0);
    vec3 exterior = vec3(0.1, 0.3, 0.5) * rings;

    // Interior blue fill
    vec3 interior = vec3(0.05, 0.15, 0.4) * (1.0 + d * 2.0);

    // Blend interior/exterior by sign of d
    vec3 col = mix(interior, exterior, step(0.0, d));

    // Edge highlight
    float edge = 1.0 - smoothstep(0.0, 0.01, abs(d));
    col = mix(col, vec3(1.0), edge);

    fragColor = vec4(col, 1.0);
}

